func:
// *** IMPORTANTE: node-red-dashboard@3.x legge msg.timestamp (ms)
// come asse X SOLO quando msg.payload è un numero puro.
// {x,y} objects NON funzionano.
var points = msg.payload;
if (!points || points.length === 0) return null;

points.forEach(function(p) {
    var ts = new Date(p._time).getTime();
    var val = parseFloat(p._value);
    if (isNaN(val)) return;
    node.send({
        topic:     p.sensor_id || "unknown",
        payload:   val,
        timestamp: ts
    });
});
return null;

// Soglie di allerta
var SOGLIA_ALTA = 30;  // °C
var SOGLIA_BASSA = 16; // °C

var points = msg.payload;
if (!points || points.length === 0) return null;

var alerts = [];
points.forEach(function(p) {
    var sid = p.sensor_id || 'unknown';
    var val = parseFloat(p._value);
    if (isNaN(val)) return;

    if (val > SOGLIA_ALTA) {
        alerts.push('\uD83D\uDD34 ALTA: ' + sid + ' = ' + val.toFixed(2) + '\u00B0C (soglia: ' + SOGLIA_ALTA + '\u00B0C)');
    } else if (val < SOGLIA_BASSA) {
        alerts.push('\uD83D\uDD35 BASSA: ' + sid + ' = ' + val.toFixed(2) + '\u00B0C (soglia: ' + SOGLIA_BASSA + '\u00B0C)');
    }
});

if (alerts.length === 0) return null;

msg.to = 'lab@its.local';
msg.from = 'iot-alert@coap-stack.local';
msg.subject = '\u26A0\uFE0F Allarme temperatura CoAP Stack (' + alerts.length + ' sensori)';
msg.payload = 'ALERT TEMPERATURA — CoAP Stack\n' +
    new Date().toISOString() + '\n\n' +
    alerts.join('\n') + '\n\n' +
    'Controlla la dashboard: http://localhost:1880/ui';
return msg;

var d = msg.payload || {};
var phase = d.phase || '?';
var eventType = d.event_type || 'unknown';
var container = d.container || 'unknown';
var duration = d.duration || '?';

var emoji = phase === 'DROP' ? '\uD83D\uDD34' : '\u2705';

msg.to = 'lab@its.local';
msg.from = 'chaos@coap-stack.local';
msg.subject = emoji + ' Chaos CoAP: ' + phase + ' \u2014 ' + eventType;

if (phase === 'DROP') {
    msg.payload = 'GUASTO SIMULATO — CoAP Stack\n\n' +
        'Evento:    ' + eventType + '\n' +
        'Container: ' + container + '\n' +
        'Durata:    ' + duration + 's\n\n' +
        'Cosa osservare:\n' +
        '  - [OFFLINE] nei log del sensore\n' +
        '  - [BUFFER]  messaggi in attesa nel buffer locale\n' +
        '  - InfluxDB smette di ricevere nuovi punti\n' +
        '  - Gateway non riceve pi\u00F9 POST CoAP\n\n' +
        'Comando per verificare:\n' +
        '  docker compose logs -f ' + container;
} else {
    msg.payload = 'RIPRISTINO RETE — CoAP Stack\n\n' +
        'Evento:    ' + eventType + '\n' +
        'Container: ' + container + '\n\n' +
        'Cosa verificare:\n' +
        '  - [BUFFER] nei log del sensore (messaggi in coda inviati)\n' +
        '  - [FLUSH]  burst di dati su InfluxDB\n' +
        '  - Il grafico mostra un gap seguito da dati compatti\n\n' +
        'Questo dimostra la resilienza del buffer locale CoAP!';
}

msg.chaos = d;
return msg;
